import sys
from collections import deque

input = sys.stdin.readline

def solve():
    n, m = map(int, input().split())
    grid = []
    lab = None
    for i in range(n):
        row = input().strip()
        grid.append(list(row))
        for j in range(len(row)):
            if row[j] == 'L':
                lab = (i, j)

    dirs = [(0,1),(0,-1),(1,0),(-1,0)]

    # free_degree[i][j] = number of free neighbors
    # non_forceable[i][j] = number of non-forceable free neighbors
    # forceable[i][j] = True/False

    free_degree = [[0]*m for _ in range(n)]
    forceable = [[False]*m for _ in range(n)]

    for i in range(n):
        for j in range(m):
            if grid[i][j] != '#':
                cnt = 0
                for di, dj in dirs:
                    ni, nj = i+di, j+dj
                    if 0 <= ni < n and 0 <= nj < m and grid[ni][nj] != '#':
                        cnt += 1
                free_degree[i][j] = cnt

    # non_forceable count starts as free_degree
    non_forceable = [row[:] for row in free_degree]

    queue = deque()

    # Lab is forceable
    li, lj = lab
    forceable[li][lj] = True
    queue.append((li, lj))

    # When lab becomes forceable, decrement neighbors
    # Process BFS
    while queue:
        i, j = queue.popleft()
        # This cell just became forceable
        # Decrement non_forceable count of all free neighbors
        for di, dj in dirs:
            ni, nj = i+di, j+dj
            if 0 <= ni < n and 0 <= nj < m and grid[ni][nj] != '#':
                if not forceable[ni][nj]:
                    non_forceable[ni][nj] -= 1
                    if non_forceable[ni][nj] <= 1:
                        forceable[ni][nj] = True
                        queue.append((ni, nj))

    # Build output
    result = []
    for i in range(n):
        row = []
        for j in range(m):
            if grid[i][j] == '#':
                row.append('#')
            elif grid[i][j] == 'L':
                row.append('L')
            elif forceable[i][j]:
                row.append('+')
            else:
                row.append('.')
        result.append(''.join(row))

    print('\n'.join(result))

t = int(input())
for _ in range(t):
    solve()

